sql:
SELECT mep_name
FROM mePs
WHERE political_group = 'ALDE';

external_knowledge:
MEPs: Members of the European Parliament; 
The European Parliament: a legislative body of the European Union; 
ALDE: Alliance of Liberals and Democrats for Europe, a political group in the European Parliament; 
Vote event: an instance where MEPs cast votes on a motion or proposal.

sql:
SELECT mep_name, country
FROM mePs
ORDER BY country, mep_name;

SELECT COUNT(*) AS num_proposals
FROM motions
WHERE proposer_group = 'ALDE';

SELECT motion_id, motion_text
FROM motions
WHERE status = 'adopted';

SELECT num_proposals
FROM proposers
WHERE mep_id = 1;

SELECT mep_name, num_proposals
FROM proposers
ORDER BY num_proposals DESC;
